// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{})
}

// ServeMux is an abstraction of http.ServeMux.
type ServeMux interface {
	HandleFunc(pattern string, handler func(http.ResponseWriter, *http.Request))
	ServeHTTP(w http.ResponseWriter, r *http.Request)
}

type StdHTTPServerOptions struct {
	BaseURL          string
	BaseRouter       ServeMux
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, m ServeMux) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseRouter: m,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, m ServeMux, baseURL string) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseURL:    baseURL,
		BaseRouter: m,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options StdHTTPServerOptions) http.Handler {
	m := options.BaseRouter

	if m == nil {
		m = http.NewServeMux()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc("GET "+options.BaseURL+"/healthz", wrapper.Healthz)
	m.HandleFunc("GET "+options.BaseURL+"/readyz", wrapper.Readyz)
	m.HandleFunc("POST "+options.BaseURL+"/v1/auth/token", wrapper.IssueAuthToken)
	m.HandleFunc("POST "+options.BaseURL+"/v1/blast-radius", wrapper.BlastRadius)
	m.HandleFunc("GET "+options.BaseURL+"/v1/components", wrapper.ListComponents)
	m.HandleFunc("POST "+options.BaseURL+"/v1/components", wrapper.UpsertComponent)
	m.HandleFunc("GET "+options.BaseURL+"/v1/components/{componentRef}/sboms", wrapper.ListSBOMsByComponent)
	m.HandleFunc("POST "+options.BaseURL+"/v1/components/{componentRef}/sboms", wrapper.SubmitSBOM)
	m.HandleFunc("GET "+options.BaseURL+"/v1/incidents", wrapper.ListIncidents)
	m.HandleFunc("GET "+options.BaseURL+"/v1/incidents/{id}", wrapper.GetIncident)
	m.HandleFunc("POST "+options.BaseURL+"/v1/incidents/{id}/remediations", wrapper.AddRemediation)
	m.HandleFunc("POST "+options.BaseURL+"/v1/incidents/{id}/transition", wrapper.TransitionIncident)
	m.HandleFunc("GET "+options.BaseURL+"/v1/iocs", wrapper.ListIoCs)
	m.HandleFunc("POST "+options.BaseURL+"/v1/iocs", wrapper.SubmitIoC)
	m.HandleFunc("GET "+options.BaseURL+"/v1/sboms/{id}", wrapper.GetSBOM)
	m.HandleFunc("GET "+options.BaseURL+"/v1/stream", wrapper.Stream)

	return m
}

